List    types       = []
List    fields      = []
List    attributes  = []
String  rootClass
String  className
String  extendsClass
boolean inClass     = false
Map     baseClasses = [:]

source.split(/\n/).each {
  // Strip '#' comments
  if ((it =~ /^#/).find()) {
    return
  }
  it = it.replaceAll(/ *#.*$/, '')
  
  if ((it =~ /^package /).find()) {
    out.println it
    out.println """
////////////////////////////////////////////////////////////////////
// File was generated using GenerateClasses.pl in tools directory
// DO NOT EDIT THIS FILE
////////////////////////////////////////////////////////////////////
"""
    return
  }
  
  def matcher = it =~ /^class +([A-Z][a-z]*)/
  if (matcher.find()) {
    rootClass = matcher[0][1]
    out.println "public abstract $it\n"
    out.println "  public abstract <T> T accept(Visitor<T> visitor);\n"
    return
  }
  
  if (it ==~ /^}/) {
    out.print "\n  public interface Visitor<T> {\n"
    types.each { out.print "    T visit$it($it ${rootClass[0].toLowerCase()}${rootClass.substring(1)});\n" }
    out.print "  }\n"
    out.println it
    return
  }
  
  if (it ==~ /^ +}/ && inClass) {
    def constructorFields = []
    def superFields = []
    if (extendsClass != rootClass) {
      if (!baseClasses[extendsClass]) {
        def forwardRefence = source.lines().grep {
          it ==~ /^ +(abstract)? *class *$extendsClass/
        }.size() > 0
        out.println "Error: ${forwardRefence ? "Forward reference to" : "Unknown"} base class $extendsClass"
        return // Need to have proper way to generate an error
      }
      superFields += baseClasses[extendsClass].collect { it[0] }
      constructorFields += baseClasses[extendsClass]
    }
    constructorFields += fields
    
    // Output constructor
    out.println "    public $className(${constructorFields.collect {"${it[1]} ${it[0]}"}.join(', ')}) {"
    if (superFields) {
      out.print """      super(${superFields.join(", ")});\n"""
    }
    fields.each {
      out.println "      this.${it[0]} = ${it[0]};"
    }
    def firstTokenArg = constructorFields.grep {name, type -> type == 'Token'}.collect { it[0] }?[0]
    // If no super field has a type Token then assign location in subclass
    if (firstTokenArg && !superFields.grep { it == firstTokenArg }) { 
      out.println "      this.location = $firstTokenArg;"
    }
    out.println "    }"
    out.println "    @Override public <T> T accept(Visitor<T> visitor) { return visitor.visit$className(this); }"
    
    // Generate toString()
    def fieldValues = constructorFields.collect { it[0] }.collect { """"$it=" + $it""" }.join(' + ", " + ')
    out.println """    @Override public String toString() { return "$className[" +${ fieldValues ? " $fieldValues +" : ""} "]"; }""";
    
    // Remember fields in case another class extends us
    baseClasses[className] = fields
    
    // Reset for next class in file
    inClass = false
    fields = []
    attributes = []
    out.println it
    return
  }
  
  matcher = it =~ /([A-Za-z][a-zA-Z<,>.]*) +([a-zA-Z0-9]+);/
  if (inClass && matcher.find()) {
    fields += [[matcher[0][2], matcher[0][1]]]
    it = it.replaceAll('^( +)', '$1public ');
  }
  matcher = it =~ /([A-Za-z][a-zA-Z<,>.]*) +@([a-zA-Z0-9]+)/
  if (inClass && matcher.find()) {
    attributes += matcher[0][2]
    it = it.replaceAll('^( +)', '$1public ');
  }
  it = it.replaceAll('@', '')
  
  matcher = it =~ /class (.*) extends +(\w*)/;
  if (matcher.find()) {
    inClass = true
    className = matcher[0][1]
    extendsClass = matcher[0][2]
    types += className
    it = it.replaceAll(/class/, 'public static class')
  }
  
  if (!inClass && !(it =~ /public/) && it =~ /^  ([A-Za-z][a-zA-Z<,>.]*) +([a-zA-Z0-9]+)/) {
    it = it.replaceAll('^( +)', '$1public ');
  }

  out.println it
}
